import base64
from google.cloud import storage, firestore, pubsub_v1
from google.oauth2 import service_account

# Service account credentials with broad permissions
CREDENTIALS = service_account.Credentials.from_service_account_file(
    'path/to/service-account-key.json',
    scopes=[
        'https://www.googleapis.com/auth/cloud-platform'
    ]
)

# Cloud Storage client
storage_client = storage.Client(credentials=CREDENTIALS)
bucket_name = 'your-bucket-name'

# Firestore client
db = firestore.Client(credentials=CREDENTIALS)

# Pub/Sub client
publisher = pubsub_v1.PublisherClient(credentials=CREDENTIALS)

def process_file(file_name):
    # Get the file from Cloud Storage
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    contents = blob.download_as_string()

    # Process the file (e.g., extract data, perform calculations)
    processed_data = base64.b64decode(contents).decode('utf-8')

    # Write to Firestore
    doc_ref = db.collection('your-collection-name').document()
    doc_ref.set({'data': processed_data})

    # Publish to Pub/Sub
    topic_path = 'your-topic-name'
    publisher.publish(topic_path, data=processed_data.encode('utf-8'))

# Trigger the function on new file uploads to Cloud Storage
def cloud_function(event, context):
    file_name = event['name']
    process_file(file_name)